 43→export function clampFolderTreeIndent(value: unknown): number {
 44→  const numeric = typeof value === 'number' ? value : Number(value);
 45→  if (!Number.isFinite(numeric)) return FOLDER_TREE_INDENT_DEFAULT;
 46→  return Math.min(FOLDER_TREE_INDENT_MAX, Math.max(FOLDER_TREE_INDENT_MIN, Math.round(numeric)));
 47→}
