  1→/**
  2→ * Service for importing and exporting folder configurations
  3→ * Follows enterprise best practices with proper validation and error handling
  4→ */
  5→import { AppError, ErrorCode } from '@/core/errors/AppError';
  6→import type { Result } from '@/core/types/common';
  7→import type { ConversationReference, Folder, FolderData } from '@/core/types/folder';
  8→import { LOCK_KEYS, importExportLock } from '@/core/utils/concurrency';
  9→import {
 10→  EXTENSION_VERSION,
 11→  type FormatVersion,
 12→  applyMigrations,
 13→  getCompatibilityInfo,
 14→  isSupportedFormat,
 15→} from '@/core/utils/version';
 16→import { SESSION_BACKUP_KEY, SESSION_BACKUP_TIMESTAMP_KEY } from '@/pages/content/folder/manager';
 17→
 18→import {
 19→  type FolderExportPayload,
 20→  type ImportOptions,
 21→  type ImportResult,
 22→  type ValidationError,
 23→  ValidationErrorType,
 24→} from '../types/import-export';
 25→
 26→const EXPORT_FORMAT: FormatVersion = 'gemini-voyager.folders.v1' as const;
 27→
 28→/**
 29→ * Service for handling folder import/export operations
 30→ */
 31→export class FolderImportExportService {
 32→  /**
 33→   * Export folder data to a downloadable JSON payload
 34→   * Uses centralized version management to ensure consistency
 35→   */
 36→  static exportToPayload(data: FolderData): FolderExportPayload {
 37→    return {
 38→      format: EXPORT_FORMAT,
 39→      exportedAt: new Date().toISOString(),
 40→      version: EXTENSION_VERSION, // Automatically synced from manifest.json
 41→      data: {
 42→        folders: data.folders,
 43→        folderContents: data.folderContents,
 44→      },
 45→    };
 46→  }
 47→
 48→  /**
 49→   * Validate import payload format and structure
 50→   * Includes version compatibility checking
 51→   */
 52→  static validatePayload(payload: unknown): Result<FolderExportPayload, ValidationError> {
 53→    // Check if payload is an object
 54→    if (!payload || typeof payload !== 'object') {
 55→      return {
 56→        success: false,
 57→        error: {
 58→          type: ValidationErrorType.INVALID_FORMAT,
 59→          message: 'Invalid payload: expected an object',
 60→          details: payload,
 61→        },
 62→      };
 63→    }
 64→
 65→    const p = payload as Record<string, unknown>;
 66→
 67→    // Check format version
 68→    if (typeof p.format !== 'string' || !isSupportedFormat(p.format)) {
 69→      return {
 70→        success: false,
 71→        error: {
 72→          type: ValidationErrorType.INVALID_VERSION,
 73→          message: `Unsupported format: expected "${EXPORT_FORMAT}", got "${p.format}"`,
 74→          details: { format: p.format },
 75→        },
 76→      };
 77→    }
 78→
 79→    // Check version compatibility
 80→    if (typeof p.version === 'string') {
 81→      const compatInfo = getCompatibilityInfo(p.version, p.format);
 82→      if (!compatInfo.compatible) {
 83→        return {
 84→          success: false,
 85→          error: {
 86→            type: ValidationErrorType.INVALID_VERSION,
 87→            message: compatInfo.reason || 'Version incompatible',
 88→            details: compatInfo,
 89→          },
 90→        };
 91→      }
 92→    }
 93→
 94→    // Check required fields
 95→    if (!p.data || typeof p.data !== 'object') {
 96→      return {
 97→        success: false,
 98→        error: {
 99→          type: ValidationErrorType.MISSING_DATA,
100→          message: 'Missing or invalid "data" field',
101→          details: p,
102→        },
103→      };
104→    }
105→
106→    const data = p.data as Record<string, unknown>;
107→
108→    // Validate folders array
109→    if (!Array.isArray(data.folders)) {
110→      return {
111→        success: false,
112→        error: {
113→          type: ValidationErrorType.CORRUPTED_DATA,
114→          message: 'Invalid "folders" field: expected an array',
115→          details: data.folders,
116→        },
117→      };
118→    }
119→
120→    // Validate folderContents object
121→    if (!data.folderContents || typeof data.folderContents !== 'object') {
122→      return {
123→        success: false,
124→        error: {
125→          type: ValidationErrorType.CORRUPTED_DATA,
126→          message: 'Invalid "folderContents" field: expected an object',
127→          details: data.folderContents,
128→        },
129→      };
130→    }
131→
132→    // Basic structure validation for folders
133→    for (const folder of data.folders) {
134→      if (!folder || typeof folder !== 'object') {
135→        return {
136→          success: false,
137→          error: {
138→            type: ValidationErrorType.CORRUPTED_DATA,
139→            message: 'Invalid folder object',
140→            details: folder,
141→          },
142→        };
143→      }
144→
145→      const f = folder as Record<string, unknown>;
146→      if (!f.id || typeof f.id !== 'string') {
147→        return {
148→          success: false,
149→          error: {
150→            type: ValidationErrorType.CORRUPTED_DATA,
151→            message: 'Folder missing valid "id" field',
152→            details: folder,
153→          },
154→        };
155→      }
156→
157→      if (!f.name || typeof f.name !== 'string') {
158→        return {
159→          success: false,
160→          error: {
161→            type: ValidationErrorType.CORRUPTED_DATA,
162→            message: 'Folder missing valid "name" field',
163→            details: folder,
164→          },
165→        };
166→      }
167→    }
168→
169→    return {
170→      success: true,
171→      data: payload as FolderExportPayload,
172→    };
173→  }
174→
175→  /**
176→   * Merge imported data with existing data
177→   * Skips duplicate folders (by ID) and conversations (by conversationId)
178→   */
179→  static mergeData(
180→    existing: FolderData,
181→    imported: FolderData,
182→  ): { merged: FolderData; stats: ImportResult } {
183→    const existingFolderIds = new Set(existing.folders.map((f) => f.id));
184→    const newFolders: Folder[] = [];
185→    let duplicatesFoldersSkipped = 0;
186→
187→    // Merge folders (skip duplicates)
188→    for (const folder of imported.folders) {
189→      if (!existingFolderIds.has(folder.id)) {
190→        newFolders.push(folder);
191→      } else {
192→        duplicatesFoldersSkipped++;
193→      }
194→    }
195→
196→    // Merge folder contents
197→    const mergedContents: Record<string, ConversationReference[]> = { ...existing.folderContents };
198→    let conversationsImported = 0;
199→    let duplicatesConversationsSkipped = 0;
200→
201→    for (const [folderId, conversations] of Object.entries(imported.folderContents)) {
202→      if (!mergedContents[folderId]) {
203→        mergedContents[folderId] = [];
204→      }
205→
206→      const existingConvIds = new Set(mergedContents[folderId].map((c) => c.conversationId));
207→
208→      for (const conv of conversations) {
209→        if (!existingConvIds.has(conv.conversationId)) {
210→          mergedContents[folderId].push(conv);
211→          conversationsImported++;
212→        } else {
213→          duplicatesConversationsSkipped++;
214→        }
215→      }
216→    }
217→
218→    const merged: FolderData = {
219→      folders: [...existing.folders, ...newFolders],
220→      folderContents: mergedContents,
221→    };
222→
223→    const stats: ImportResult = {
224→      foldersImported: newFolders.length,
225→      conversationsImported,
226→      duplicatesFoldersSkipped,
227→      duplicatesConversationsSkipped,
228→    };
229→
230→    return { merged, stats };
231→  }
232→
233→  /**
234→   * Import folder data from payload
235→   * @param payload - The import payload
236→   * @param currentData - Current folder data
237→   * @param options - Import options (strategy, backup)
238→   * @returns Result with import statistics
239→   *
240→   * Note: This method should be called through importFromPayloadWithLock for concurrency protection
241→   */
242→  private static importFromPayloadInternal(
243→    payload: FolderExportPayload,
244→    currentData: FolderData,
245→    options: ImportOptions,
246→  ): Result<{ data: FolderData; stats: ImportResult }> {
247→    try {
248→      const { strategy, createBackup = true } = options;
249→
250→      // Apply any necessary data migrations
251→      let importData = payload.data;
252→      const migrationsApplied: string[] = [];
253→
254→      if (payload.version) {
255→        try {
256→          const migrationResult = applyMigrations(payload.data, payload.version);
257→          importData = migrationResult.data as FolderData;
258→          migrationsApplied.push(...migrationResult.migrationsApplied);
259→
260→          if (migrationsApplied.length > 0) {
261→            console.log('Applied migrations:', migrationsApplied);
262→          }
263→        } catch (error) {
264→          console.warn('Migration failed, using original data:', error);
265→        }
266→      }
267→
268→      // Create backup if requested
269→      let backupData: FolderData | null = null;
270→      if (createBackup) {
271→        backupData = {
272→          folders: [...currentData.folders],
273→          folderContents: { ...currentData.folderContents },
274→        };
275→      }
276→
277→      let resultData: FolderData;
278→      let stats: ImportResult;
279→
280→      if (strategy === 'overwrite') {
281→        // Overwrite: completely replace with imported data
282→        resultData = {
283→          folders: [...importData.folders],
284→          folderContents: { ...importData.folderContents },
285→        };
286→
287→        const totalConversations = Object.values(importData.folderContents).reduce(
288→          (sum, convs) => sum + convs.length,
289→          0,
290→        );
291→
292→        stats = {
293→          foldersImported: importData.folders.length,
294→          conversationsImported: totalConversations,
295→          backupCreated: createBackup,
296→        };
297→      } else {
298→        // Merge: combine with existing data
299→        const mergeResult = this.mergeData(currentData, importData);
300→        resultData = mergeResult.merged;
301→        stats = {
302→          ...mergeResult.stats,
303→          backupCreated: createBackup,
304→        };
305→      }
306→
307→      // Store backup in sessionStorage if created
308→      if (backupData) {
309→        try {
310→          sessionStorage.setItem(SESSION_BACKUP_KEY, JSON.stringify(backupData));
311→          sessionStorage.setItem(SESSION_BACKUP_TIMESTAMP_KEY, new Date().toISOString());
312→        } catch (error) {
313→          // Backup storage failed, but continue with import
314→          console.warn('Failed to store backup in sessionStorage', error);
315→        }
316→      }
317→
318→      return {
319→        success: true,
320→        data: { data: resultData, stats },
321→      };
322→    } catch (error) {
323→      return {
324→        success: false,
325→        error: new AppError(ErrorCode.UNKNOWN_ERROR, 'Import failed', { originalError: error }),
326→      };
327→    }
328→  }
329→
330→  /**
331→   * Import folder data from payload with concurrency protection
332→   * This is the public method that should be used for imports
333→   * @param payload - The import payload
334→   * @param currentData - Current folder data
335→   * @param options - Import options (strategy, backup)
336→   * @returns Result with import statistics
337→   */
338→  static async importFromPayload(
339→    payload: FolderExportPayload,
340→    currentData: FolderData,
341→    options: ImportOptions,
342→  ): Promise<Result<{ data: FolderData; stats: ImportResult }>> {
343→    // Use lock to prevent concurrent imports
344→    return await importExportLock.withLock(
345→      LOCK_KEYS.FOLDER_IMPORT,
346→      () => Promise.resolve(this.importFromPayloadInternal(payload, currentData, options)),
347→      30000, // 30 second timeout
348→    );
349→  }
