351→  /**
352→   * Generate filename for export with timestamp
353→   */
354→  static generateExportFilename(): string {
355→    const pad = (n: number) => String(n).padStart(2, '0');
356→    const d = new Date();
357→    const y = d.getFullYear();
358→    const m = pad(d.getMonth() + 1);
359→    const day = pad(d.getDate());
360→    const hh = pad(d.getHours());
361→    const mm = pad(d.getMinutes());
362→    const ss = pad(d.getSeconds());
363→    return `gemini-voyager-folders-${y}${m}${day}-${hh}${mm}${ss}.json`;
364→  }
365→
366→  /**
367→   * Download JSON file to user's computer
368→   */
369→  static downloadJSON(payload: FolderExportPayload, filename?: string): void {
370→    const data = JSON.stringify(payload, null, 2);
371→    const blob = new Blob([data], { type: 'application/json;charset=utf-8' });
372→    const url = URL.createObjectURL(blob);
373→    const a = document.createElement('a');
374→    a.href = url;
375→    a.download = filename || this.generateExportFilename();
376→    document.body.appendChild(a);
377→    a.click();
378→    setTimeout(() => {
379→      try {
380→        document.body.removeChild(a);
381→      } catch {
382→        /* ignore */
383→      }
384→      URL.revokeObjectURL(url);
385→    }, 0);
386→  }
387→
388→  /**
389→   * Read and parse JSON file from user upload
390→   */
391→  static async readJSONFile(file: File): Promise<Result<unknown>> {
392→    try {
393→      const text = await file.text();
394→      const parsed = JSON.parse(text);
395→      return {
396→        success: true,
397→        data: parsed,
398→      };
399→    } catch (error) {
400→      return {
401→        success: false,
402→        error: new AppError(ErrorCode.VALIDATION_ERROR, 'Failed to parse JSON file', {
403→          originalError: error,
404→        }),
405→      };
406→    }
407→  }
408→
409→  /**
410→   * Restore from backup stored in sessionStorage
411→   */
412→  static restoreFromBackup(): Result<FolderData> {
413→    try {
414→      const backupStr = sessionStorage.getItem(SESSION_BACKUP_KEY);
415→      if (!backupStr) {
416→        return {
417→          success: false,
418→          error: new AppError(ErrorCode.STORAGE_READ_FAILED, 'No backup found'),
419→        };
420→      }
421→
422→      const backup = JSON.parse(backupStr) as FolderData;
423→      return {
424→        success: true,
425→        data: backup,
426→      };
427→    } catch (error) {
428→      return {
429→        success: false,
430→        error: new AppError(ErrorCode.UNKNOWN_ERROR, 'Failed to restore backup', {
431→          originalError: error,
432→        }),
433→      };
434→    }
435→  }
436→
437→  /**
438→   * Clear backup from sessionStorage
439→   */
440→  static clearBackup(): void {
441→    try {
442→      sessionStorage.removeItem(SESSION_BACKUP_KEY);
443→      sessionStorage.removeItem(SESSION_BACKUP_TIMESTAMP_KEY);
444→    } catch {
445→      /* ignore */
446→    }
447→  }
448→
449→  /**
450→   * Check if backup exists
451→   */
452→  static hasBackup(): boolean {
453→    try {
454→      return sessionStorage.getItem(SESSION_BACKUP_KEY) !== null;
455→    } catch {
456→      return false;
457→    }
458→  }
459→
460→  /**
461→   * Get backup timestamp
462→   */
463→  static getBackupTimestamp(): string | null {
464→    try {
465→      return sessionStorage.getItem(SESSION_BACKUP_TIMESTAMP_KEY);
466→    } catch {
467→      return null;
468→    }
469→  }
470→}
