 3→type ClipboardWriteLike = Pick<Clipboard, 'write'>;
 4→type ClipboardItemLike = new (items: Record<string, Blob>) => ClipboardItem;
 5→
 6→export type CopyElementAsImageOptions = {
 7→  clipboard?: ClipboardWriteLike | null;
 8→  ClipboardItemCtor?: ClipboardItemLike | null;
 9→};
10→
11→function resolveClipboardDependencies(options?: CopyElementAsImageOptions): {
12→  clipboard: ClipboardWriteLike | null;
13→  ClipboardItemCtor: ClipboardItemLike | null;
14→} {
15→  const clipboard = options?.clipboard ?? navigator.clipboard ?? null;
16→  const globalClipboardItem = (globalThis as unknown as { ClipboardItem?: ClipboardItemLike })
17→    .ClipboardItem;
18→  const ClipboardItemCtor = options?.ClipboardItemCtor ?? globalClipboardItem ?? null;
19→
20→  return { clipboard, ClipboardItemCtor };
21→}
22→
23→export async function copyImageBlobToClipboard(
24→  blob: Blob,
25→  options?: CopyElementAsImageOptions,
26→): Promise<void> {
27→  const { clipboard, ClipboardItemCtor } = resolveClipboardDependencies(options);
28→  if (!clipboard?.write || !ClipboardItemCtor) {
29→    throw new Error('Clipboard image copy is not supported in this browser');
30→  }
31→
32→  const item = new ClipboardItemCtor({ [blob.type || 'image/png']: blob });
33→  await clipboard.write([item]);
34→}
35→
36→export function downloadImageBlob(blob: Blob, filename: string): void {
37→  const url = URL.createObjectURL(blob);
38→  const anchor = document.createElement('a');
39→  anchor.href = url;
40→  anchor.download = filename.toLowerCase().endsWith('.png') ? filename : `${filename}.png`;
41→  document.body.appendChild(anchor);
42→  anchor.click();
43→  setTimeout(() => {
44→    try {
45→      document.body.removeChild(anchor);
46→    } catch {
47→      /* ignore */
48→    }
49→    URL.revokeObjectURL(url);
50→  }, 0);
51→}
52→
53→export async function copyElementAsImageToClipboard(
54→  target: HTMLElement,
55→  options?: CopyElementAsImageOptions,
56→): Promise<void> {
57→  const blob = await renderElementToImageBlob(target, {
58→    enableSanitizedFallback: true,
59→  });
60→  await copyImageBlobToClipboard(blob, options);
61→}
