1766→  private setupMutationObserver(): void {
1767→    if (!this.sidebarContainer) return;
1768→
1769→    // Disconnect existing observer to prevent duplicates
1770→    if (this.conversationObserver) {
1771→      this.conversationObserver.disconnect();
1772→      this.conversationObserver = null;
1773→    }
1774→
1775→    this.conversationObserver = new MutationObserver((mutations) => {
1776→      // 1. Handle added conversations (always safe)
1777→      mutations.forEach((mutation) => {
1778→        mutation.addedNodes.forEach((node) => {
1779→          if (node instanceof HTMLElement) {
1780→            // Check if the node itself is a conversation
1781→            if (node.matches('[data-test-id="conversation"]')) {
1782→              this.makeConversationDraggable(node);
1783→              this.applyHideArchivedToConversation(node);
1784→              // Cancel pending removal for this conversation (it's back!)
1785→              this.cancelPendingRemovalForElement(node);
1786→            }
1787→            // Also check for conversations within the node
1788→            const conversations = node.querySelectorAll('[data-test-id="conversation"]');
1789→            conversations.forEach((conv) => {
1790→              const convElement = conv as HTMLElement;
1791→              this.makeConversationDraggable(convElement);
1792→              // Apply hide archived setting to newly added conversations
1793→              this.applyHideArchivedToConversation(convElement);
1794→              // Cancel pending removal for this conversation (it's back!)
1795→              this.cancelPendingRemovalForElement(convElement);
1796→            });
1797→          }
1798→        });
1799→      });
1800→
1801→      // 2. Handle removed conversations with safeguards
1802→      // CRITICAL FIX: Prevent data loss when network disconnects or UI refreshes
1803→
1804→      // Check 1: If offline, assume removals are due to network error
1805→      if (!navigator.onLine) {
1806→        this.debug('Network offline, ignoring conversation removals to prevent data loss');
1807→        return;
1808→      }
1809→
1810→      // Check 2: Calculate total conversations being removed in this batch
1811→      let totalRemovedCount = 0;
1812→      const nodesWithRemovals: HTMLElement[] = [];
1813→
1814→      mutations.forEach((mutation) => {
1815→        mutation.removedNodes.forEach((node) => {
1816→          if (node instanceof HTMLElement) {
1817→            const isConv = node.matches('[data-test-id="conversation"]');
1818→            // Check if it contains conversations (e.g. a container was removed)
1819→            const containedConvsCount = node.querySelectorAll(
1820→              '[data-test-id="conversation"]',
1821→            ).length;
1822→
1823→            if (isConv) {
1824→              totalRemovedCount++;
1825→              nodesWithRemovals.push(node);
1826→            } else if (containedConvsCount > 0) {
1827→              totalRemovedCount += containedConvsCount;
1828→              nodesWithRemovals.push(node);
1829→            }
1830→          }
1831→        });
1832→      });
1833→
1834→      // If no conversations were removed, we're done
1835→      if (totalRemovedCount === 0) return;
1836→
1837→      // Check 3: If multiple conversations are removed at once, it's likely a UI refresh/clear
1838→      // Users typically delete conversations one by one.
1839→      // EXCEPTION: If we are in multi-select mode, the user might be performing a bulk delete.
1840→      if (totalRemovedCount > 1 && !this.isMultiSelectMode) {
1841→        this.debugWarn(
1842→          `Ignored bulk removal of ${totalRemovedCount} conversations - likely UI refresh`,
1843→        );
1844→        return;
1845→      }
1846→
1847→      // NEW: Instead of immediately removing, schedule a delayed check
1848→      // This prevents false positives when Gemini temporarily removes/re-adds DOM elements during UI updates
1849→      nodesWithRemovals.forEach((node) => {
1850→        const conversations = node.matches('[data-test-id="conversation"]')
1851→          ? [node]
1852→          : Array.from(node.querySelectorAll('[data-test-id="conversation"]'));
1853→
1854→        conversations.forEach((conv) => {
1855→          // Extract conversation ID from the removed element
1856→          const conversationId = this.extractConversationIdFromElement(conv);
1857→
1858→          if (conversationId) {
1859→            this.debug('Detected potential conversation removal:', conversationId);
1860→            // Schedule delayed removal check
1861→            this.scheduleConversationRemovalCheck(conversationId);
1862→          }
1863→        });
1864→      });
1865→    });
1866→
1867→    this.conversationObserver.observe(this.sidebarContainer, {
1868→      childList: true,
1869→      subtree: true,
1870→    });
1871→  }
