          setForkEnabled(res?.[StorageKeys.FORK_ENABLED] === true);
          setUpsellHiderEnabled(res?.[StorageKeys.UPSELL_HIDER_ENABLED] === true);

          // Width enabled flags — auto-enable if user previously customized the width
          setChatWidthEnabled(
