    try {
      const normalized = domain
        .trim()
        .toLowerCase()
        .replace(/^https?:\/\//, '')
        .replace(/^www\./, '')
        .replace(/\/.*$/, '')
        .replace(/^\*\./, '');
      if (!normalized) return null;
      return [`https://*.${normalized}/*`, `http://*.${normalized}/*`];
    } catch {
      return null;
